CREATE TRIGGER LG_COSTDISTPEG_INS_323_01 ON LG_323_01_COSTDISTPEG
FOR INSERT
AS
DECLARE @STTRANSREF INT
DECLARE @RECVSTTRANSREF INT
DECLARE @ADDEXPENSE FLOAT
DECLARE @ADDRPEXPENSE FLOAT
DECLARE @ADDEXPENSEUFRS FLOAT
DECLARE @ADDRPEXPENSEUFRS FLOAT
DECLARE @TRANTYPE  SMALLINT
DECLARE @PRDTRANSREF INT
SELECT @STTRANSREF = I.STTRANSREF,
       @RECVSTTRANSREF = I.RECVSTTRANSREF,
       @ADDEXPENSE    = I.ADDEXPENSE,
       @ADDRPEXPENSE    = I.ADDRPEXPENSE,
       @ADDEXPENSEUFRS    = I.ADDEXPENSEUFRS,
       @ADDRPEXPENSEUFRS  = I.ADDRPEXPENSEUFRS,
       @TRANTYPE = I.TRANTYPE,
      @PRDTRANSREF = I.PRDCOSTTRREF
       FROM INSERTED I
EXECUTE LG_UPDATE_COSTPROC_323_01  @TRANTYPE, @STTRANSREF,@PRDTRANSREF, @RECVSTTRANSREF, @ADDEXPENSE, @ADDRPEXPENSE, @ADDEXPENSEUFRS, @ADDRPEXPENSEUFRS, 1
